INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('after', 'op', 21, 'OP', 'Basic English 操作/关系词', 'a core operation or relation word in Basic English', 'The word "after" can help make a simple sentence.', '"after" 这个词可以帮助组成一个简单句。', '[{"w":"across","def":"across: 相关的动作或关系词","vs":"与 after 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"across\" / \"after\" 的替换练习"},{"w":"against","def":"against: 可帮助扩展句型的基础词","vs":"与 after 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"against\" / \"after\" 的替换练习"},{"w":"among","def":"among: 同一组 Basic English 操作词","vs":"与 after 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"among\" / \"after\" 的替换练习"}]'),
